import{_ as t,o as d,c as r,a3 as c}from"./chunks/framework.DG2GXa4n.js";const l=JSON.parse('{"title":"Сравнение с farfetched","description":"","frontmatter":{},"headers":[],"relativePath":"ru/guide/vs-farfetched.md","filePath":"ru/guide/vs-farfetched.md","lastUpdated":1781015796000}'),o={name:"ru/guide/vs-farfetched.md"};function a(f,e,s,n,h,i){return d(),r("div",null,[...e[0]||(e[0]=[c('<h1 id="сравнение-с-farfetched" tabindex="-1">Сравнение с farfetched <a class="header-anchor" href="#сравнение-с-farfetched" aria-label="Permalink to &quot;Сравнение с farfetched&quot;">​</a></h1><p><a href="https://ff.effector.dev" target="_blank" rel="noreferrer">farfetched</a> — самый полный инструмент получения данных для effector и очевидная точка отсчёта. Он <strong>с открытым исходным кодом и не заархивирован</strong> — но темп замедлился: всё ещё pre-1.0, изначальная цель «1.0 к концу 2024» сдвинута, бэклог issues растёт. <code>effector-refetch</code> существует, чтобы быть <strong>поддерживаемым, effect-first</strong> вариантом с меньшей и более дружелюбной поверхностью — а не чтобы заявлять, что farfetched мёртв.</p><table tabindex="0"><thead><tr><th></th><th>farfetched</th><th>effector-refetch</th></tr></thead><tbody><tr><td>единица работы</td><td>внутренний event-based исполнитель</td><td>ваш реальный <code>Effect</code> — first-class</td></tr><tr><td>основной вход</td><td><code>handler</code> (оборачивается); <code>effect</code> — один из путей</td><td><code>effect</code> — основной вход; <code>handler</code> — сахар</td></tr><tr><td>retry / cache / concurrency</td><td>отдельные операторы</td><td>inline-опции <strong>и</strong> отдельные операторы</td></tr><tr><td>sourced-конфиг</td><td>sourced-поля</td><td>реактивный <code>Store</code> для <code>enabled</code> / <code>concurrency</code> / <code>retry.times</code> / <code>cache.staleAfter</code></td></tr><tr><td>валидация</td><td><code>contract</code>, <code>validate</code></td><td><code>contract</code> (zod / Standard Schema) + <code>validate</code></td></tr><tr><td>декларативный HTTP</td><td><code>createJsonQuery</code></td><td><code>createJsonQuery</code> (глобальный <code>fetch</code>, без зависимостей)</td></tr><tr><td>пагинация</td><td>—</td><td><code>createInfiniteQuery</code></td></tr><tr><td>отмена</td><td>abort + discard</td><td>реальный <code>AbortSignal</code> через <code>createRequestFx</code></td></tr><tr><td>биндинги</td><td>react / solid / vue</td><td><code>useUnit(query)</code> (react + vue) + хелперы <code>useQuery</code></td></tr></tbody></table><p><strong>Честный компромисс.</strong> В некоторых местах farfetched всё ещё богаче (sourced везде, экосистема JSON-контрактов, зрелость). <code>effector-refetch</code> проще, ближе к голому effector («у меня уже есть эффект, оберни его») и нацелен дойти до стабильной 1.0. Нужна вся поверхность farfetched сегодня — берите его; хотите effect-first API на поддерживаемом проекте — берите это.</p>',4)])])}const _=t(o,[["render",a]]);export{l as __pageData,_ as default};
